import{_ as e,o,c as r,O as t}from"./chunks/framework.bdcb0ee1.js";const c=JSON.parse('{"title":"Groups & Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"administration/users/groups.md","filePath":"administration/users/groups.md","lastUpdated":1773167217000}'),s={name:"administration/users/groups.md"},a=t('<h1 id="groups-permissions" tabindex="-1">Groups &amp; Permissions <a class="header-anchor" href="#groups-permissions" aria-label="Permalink to &quot;Groups &amp; Permissions&quot;">​</a></h1><p>User groups are the foundation of ForumSpark&#39;s permission system. Every user belongs to a primary group, and can optionally belong to one or more secondary groups. Groups determine what a user can see and do across your board.</p><p>You can manage groups from the <strong>Users &amp; Groups</strong> section in the Admin Control Panel.</p><nav class="table-of-contents"><ul><li><a href="#creating-a-group">Creating a Group</a></li><li><a href="#forum-permissions">Forum Permissions</a></li><li><a href="#default-groups">Default Groups</a></li><li><a href="#secondary-groups">Secondary Groups</a></li><li><a href="#auto-promotion">Auto-Promotion</a></li><li><a href="#staff-page">Staff Page</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="creating-a-group" tabindex="-1">Creating a Group <a class="header-anchor" href="#creating-a-group" aria-label="Permalink to &quot;Creating a Group&quot;">​</a></h2><p>To create a new group, go to <strong>Users &amp; Groups &gt; Groups</strong> and click <strong>Create Group</strong>.</p><p>Fill in the following fields:</p><ul><li><strong>Name</strong>: The name of the group (max 255 characters). For example, &quot;Moderators&quot; or &quot;VIP Members&quot;.</li><li><strong>Title Format</strong>: Controls how the group name is displayed alongside the username. Use <code>%s</code> as a placeholder for the username. For example, <code>&lt;strong&gt;%s&lt;/strong&gt;</code> would bold the username for members of this group.</li><li><strong>Custom CSS Classes</strong>: Optional CSS classes applied to the username when displayed (max 255 characters). This lets you colour-code groups in post listings.</li><li><strong>Sort Order</strong>: Controls the display order in group listings. Lower numbers appear first.</li><li><strong>Show on Staff Page</strong>: If enabled, members of this group will appear on the public Staff page.</li></ul><img width="1940" height="1517" alt="image" src="https://github.com/user-attachments/assets/23584ac0-7217-4b5e-a5c6-87e0b3d3c567"><h2 id="forum-permissions" tabindex="-1">Forum Permissions <a class="header-anchor" href="#forum-permissions" aria-label="Permalink to &quot;Forum Permissions&quot;">​</a></h2><p>Each group can be assigned specific permissions on a per-forum basis. This gives you fine-grained control over which groups can access which forums.</p><p>The available permission types are:</p><table><thead><tr><th>Permission</th><th>Description</th></tr></thead><tbody><tr><td>View</td><td>Whether the group can see the forum exists in the forum listing.</td></tr><tr><td>Read</td><td>Whether the group can open and read topics within the forum.</td></tr><tr><td>Reply</td><td>Whether the group can post replies to existing topics.</td></tr><tr><td>Start</td><td>Whether the group can create new topics in the forum.</td></tr></tbody></table><p>Permissions are managed from the forum edit page in <a href="/administration/structure/section-management.html">Section Management</a>.</p><h2 id="default-groups" tabindex="-1">Default Groups <a class="header-anchor" href="#default-groups" aria-label="Permalink to &quot;Default Groups&quot;">​</a></h2><p>Two groups have special roles:</p><ul><li><strong>Guest User Group</strong>: Applied to all unauthenticated visitors. Controls what non-logged-in users can see.</li><li><strong>Default User Group</strong>: Automatically assigned to users when they register.</li></ul><p>These groups can be changed in <a href="/administration/config/settings.html">Board Settings</a> under <strong>Default user groups</strong>. Groups currently assigned as a default cannot be deleted.</p><h2 id="secondary-groups" tabindex="-1">Secondary Groups <a class="header-anchor" href="#secondary-groups" aria-label="Permalink to &quot;Secondary Groups&quot;">​</a></h2><p>Users can belong to multiple groups at the same time. Every user has one <strong>primary group</strong>, and can be assigned to additional <strong>secondary groups</strong>.</p><p>When determining permissions, ForumSpark checks all of a user&#39;s groups (primary and secondary). If any group grants a permission, the user has that permission.</p><p>Secondary groups are assigned from the user edit page in the Admin CP.</p><h2 id="auto-promotion" tabindex="-1">Auto-Promotion <a class="header-anchor" href="#auto-promotion" aria-label="Permalink to &quot;Auto-Promotion&quot;">​</a></h2><p>Groups can be configured to automatically promote users to a higher group based on their post count.</p><p>To set up auto-promotion:</p><ol><li>Edit the group you want to promote <strong>from</strong>.</li><li>Set <strong>Promotes to Group</strong> to the target group.</li><li>Set <strong>Minimum Posts</strong> to the number of posts required to trigger the promotion.</li></ol><p>When a user&#39;s post count reaches the threshold, they are automatically moved to the target group. This is useful for creating tiered membership levels (e.g., &quot;New Member&quot; → &quot;Regular&quot; → &quot;Senior&quot;).</p><h2 id="staff-page" tabindex="-1">Staff Page <a class="header-anchor" href="#staff-page" aria-label="Permalink to &quot;Staff Page&quot;">​</a></h2><p>Groups with <strong>Show on Staff Page</strong> enabled will have their members listed on the public Staff page. This is typically used for administrators, moderators, and other staff-level groups.</p><p>Members are displayed grouped by their group, in the order defined by the group&#39;s sort order.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Groups cannot be deleted while they are assigned as the default or guest group.</li><li>The title format field must contain exactly one <code>%s</code> placeholder.</li><li>Permissions are additive — if a user belongs to multiple groups, they receive the combined permissions of all their groups.</li><li>Changes to group permissions take effect immediately for all members of the group.</li></ul>',32),i=[a];function n(l,u,p,h,d,g){return o(),r("div",null,i)}const f=e(s,[["render",n]]);export{c as __pageData,f as default};
